		if err != nil {
			return err
		}

		info, err := client.ConnectInfo(sandbox.ID)
		if err != nil {
			return err
		}

		if err := waitForSSH(info.Host, info.Port); err != nil {
			return err
		}

		cfg, err := config.Load()
		if err != nil {
			return err
		}
		prefs := cfg.LoadPreferences()

