// checkHostReachable does a fast ping to verify the host is up before waiting
// for SSH. This catches common issues like Tailscale being down or the network
// being unreachable without making the user wait for the full SSH timeout.
func checkHostReachable(host string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, "ping", "-c", "1", "-W", "2", host)
	if err := cmd.Run(); err != nil {
