// checkHostReachable does a fast TCP probe to verify the host is up before
// waiting for SSH. This catches common issues like Tailscale being down or
// the network being unreachable without making the user wait for the full
// SSH timeout.
func checkHostReachable(host string) error {
	// Quick DNS / route check — try to reach any port. We don't need a
	// successful connection, just confirmation the host is routable.
	// A "connection refused" is fine (host is up, port closed).
	conn, err := net.DialTimeout("tcp", net.JoinHostPort(host, "0"), 3*time.Second)
	if conn != nil {
		conn.Close()
		return nil
	}
	if err != nil {
		// "connection refused" means the host is reachable but the port is
		// closed — that's fine, the host is up.
		if opErr, ok := err.(*net.OpError); ok {
			if sysErr, ok := opErr.Err.(*os.SyscallError); ok {
				if sysErr.Syscall == "connect" {
					// ECONNREFUSED = host is reachable
					return nil
				}
			}
		}
		return fmt.Errorf("host %s is not reachable — is Tailscale running and connected?\n  %w", host, err)
	}
	return nil
}

