}

func splitArgs(args []string) (string, []string) {
	if len(args) == 0 {
		return "", nil
	}
	return args[0], args[1:]
}

func resolveProtocol(cmd *cobra.Command, cfg *config.Config, host string, port int, user, extraArgs string) string {
